INSERT INTO "notes" ("id","note_date","pm","project_name","notes","year","synced_at") VALUES(557,1772409600,'Rai','Caturindo',replace('1.1 String PV Modul masih terkendala tidak ada tegangan dan arus \n 2. 2 CCTV masih ada yang belum terbaca\n 3. Hari ini rencana akan di cek','\n',char(10)),2025,1772702509);
