INSERT INTO "notes" ("id","note_date","pm","project_name","notes","year","synced_at") VALUES(560,1772409600,'Rai','BAS',replace('1. Pekerjaan Mounting dan install walkway sudah 100%\n 2. Hari ini team sudah mulai juga pekerjaan install shelterinverter\n 3. sempat ada perubahan gambar, pada layout pv tapi sudah dikomunikasikan kembali dengan team bas','\n',char(10)),2026,1772702509);
